public static RunListener wrapIfThreadSafe(RunListener listener) {
    // Check if the listener is annotated with ThreadSafe
    boolean isThreadSafe = listener.getClass().isAnnotationPresent(ThreadSafe.class);

    // If it's not, create a new SynchronizedRunListener wrapping the original listener and this instance
    return isThreadSafe ? listener : new SynchronizedRunListener(listener, RunListener.this);
}

